import React from 'react'

require('./Gallery.css')

const Images = ['ogun1.jpg', 'ogun2.jpg', 'ogun3.jpg', 'ogun4.jpg', 'ogun5.jpg', 'ogun6.jpg', 'ogun7.jpg', 'ogun8.jpg', 'ogun9.jpg']
const Videos = [
  {
    src: 'esw6QLSl9_E',
    title: 'ololo live',
  },
  {
    src: '-DhPBYC8VAY',
    title: 'ashiri dudu live',
  },
  {
    src: 'QzRjVFw8yaY',
    title: 'efon live',
  },
  {
    src: 'RUssvHLdBT8',
    title: 'resurrection live',
  },
]

const ImagesComponent = Images.map((image, key) =>
  <img key={key} data-src={require('../../img/' + image)} className='lazy' alt='ogun' />
)

const VideosComponent = Videos.map((video, key) => (
  <div className="embed-responsive embed-responsive-16by9" key={key}>
    <iframe className="embed-responsive-item lazy"
      data-src={'https://www.youtube.com/embed/' + video.src}
      allow="accelerometer; autoplay; encrypted-media; gyroscope; picture-in-picture"
      allowFullScreen
      title={video.title}
    />
  </div>)
)

export default class Gallery extends React.Component {
  render () {
    return (
      <section id='gallery' className='container-fluid section'>

        <div className='gallery'>
          {ImagesComponent}
        </div>

        <div className='gallery video-gallery'>
          {VideosComponent}
        </div>
      </section>
    )
  }
}
